/**
 * Template Marketplace Engine
 *
 * Types, validation, filtering and search logic for the template marketplace.
 * Pure functions — no database, no API calls.
 */

// ─── Types ─────────────────────────────────────────────────────────────────────

export type TemplateCategory =
  | 'education'
  | 'business'
  | 'marketing'
  | 'social_media'
  | 'explainer'
  | 'tutorial'
  | 'presentation'
  | 'ecommerce'
  | 'personal'
  | 'other';

export interface MarketplaceTemplate {
  id: string;
  title: string;
  description: string;
  category: TemplateCategory;
  tags: string[];
  thumbnail: string;
  authorId: string;
  authorName: string;
  slidesCount: number;
  duration: number; // estimated seconds
  resolution: '720p' | '1080p' | '4k';
  format: 'presentation' | 'social' | 'explainer' | 'tutorial' | 'marketing';
  price: number; // 0 = free
  currency: 'BRL' | 'USD';
  downloads: number;
  rating: number; // 0-5
  reviewCount: number;
  featured: boolean;
  communitySubmission: boolean;
  status: 'draft' | 'pending_review' | 'published' | 'rejected';
  createdAt: string; // ISO date
  updatedAt: string;
}

export interface MarketplaceFilter {
  category?: TemplateCategory;
  search?: string;
  minRating?: number;
  priceRange?: 'free' | 'paid' | 'all';
  format?: MarketplaceTemplate['format'];
  sortBy?: 'newest' | 'popular' | 'rating' | 'price_asc' | 'price_desc';
  featured?: boolean;
  page?: number;
  pageSize?: number;
}

export interface MarketplaceSearchResult {
  templates: MarketplaceTemplate[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
  hasMore: boolean;
}

export interface TemplateReview {
  id: string;
  templateId: string;
  userId: string;
  userName: string;
  rating: number;
  comment: string;
  createdAt: string;
}

export interface TemplateSubmission {
  title: string;
  description: string;
  category: TemplateCategory;
  tags: string[];
  format: MarketplaceTemplate['format'];
  price: number;
  slidesData: unknown;
}

// ─── Constants ─────────────────────────────────────────────────────────────────

export const TEMPLATE_CATEGORIES: {
  value: TemplateCategory;
  label: string;
  icon: string;
}[] = [
  { value: 'education', label: 'Educação', icon: '📚' },
  { value: 'business', label: 'Negócios', icon: '💼' },
  { value: 'marketing', label: 'Marketing', icon: '📢' },
  { value: 'social_media', label: 'Redes Sociais', icon: '📱' },
  { value: 'explainer', label: 'Explicativo', icon: '💡' },
  { value: 'tutorial', label: 'Tutorial', icon: '🎓' },
  { value: 'presentation', label: 'Apresentação', icon: '📊' },
  { value: 'ecommerce', label: 'E-commerce', icon: '🛒' },
  { value: 'personal', label: 'Pessoal', icon: '👤' },
  { value: 'other', label: 'Outros', icon: '📁' },
];

const VALID_CATEGORIES = new Set<string>(
  TEMPLATE_CATEGORIES.map((c) => c.value)
);

const VALID_FORMATS = new Set<string>([
  'presentation',
  'social',
  'explainer',
  'tutorial',
  'marketing',
]);

export const DEFAULT_PAGE_SIZE = 12;

// ─── Filtering ─────────────────────────────────────────────────────────────────

/**
 * Pure filtering + sorting + pagination over an array of templates.
 */
export function filterTemplates(
  templates: MarketplaceTemplate[],
  filter: MarketplaceFilter
): MarketplaceSearchResult {
  let results = [...templates];

  // Category filter
  if (filter.category) {
    results = results.filter((t) => t.category === filter.category);
  }

  // Text search
  if (filter.search && filter.search.trim().length > 0) {
    results = searchTemplates(results, filter.search);
  }

  // Minimum rating
  if (filter.minRating !== undefined && filter.minRating > 0) {
    results = results.filter((t) => t.rating >= (filter.minRating as number));
  }

  // Price range
  if (filter.priceRange === 'free') {
    results = results.filter((t) => t.price === 0);
  } else if (filter.priceRange === 'paid') {
    results = results.filter((t) => t.price > 0);
  }

  // Format filter
  if (filter.format) {
    results = results.filter((t) => t.format === filter.format);
  }

  // Featured filter
  if (filter.featured === true) {
    results = results.filter((t) => t.featured);
  }

  // Sort
  if (filter.sortBy) {
    results = sortTemplates(results, filter.sortBy);
  }

  // Paginate
  const page = filter.page ?? 1;
  const pageSize = filter.pageSize ?? DEFAULT_PAGE_SIZE;
  return paginateResults(results, page, pageSize);
}

// ─── Search ────────────────────────────────────────────────────────────────────

/**
 * Case-insensitive fuzzy search across title, description, tags, and authorName.
 */
export function searchTemplates(
  templates: MarketplaceTemplate[],
  query: string
): MarketplaceTemplate[] {
  const normalised = query.toLowerCase().trim();
  if (normalised.length === 0) return templates;

  return templates.filter((t) => {
    const haystack = [
      t.title,
      t.description,
      t.authorName,
      ...t.tags,
    ]
      .join(' ')
      .toLowerCase();
    return haystack.includes(normalised);
  });
}

// ─── Sorting ───────────────────────────────────────────────────────────────────

export function sortTemplates(
  templates: MarketplaceTemplate[],
  sortBy: MarketplaceFilter['sortBy']
): MarketplaceTemplate[] {
  const sorted = [...templates];

  switch (sortBy) {
    case 'newest':
      sorted.sort(
        (a, b) =>
          new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime()
      );
      break;
    case 'popular':
      sorted.sort((a, b) => b.downloads - a.downloads);
      break;
    case 'rating':
      sorted.sort((a, b) => b.rating - a.rating);
      break;
    case 'price_asc':
      sorted.sort((a, b) => a.price - b.price);
      break;
    case 'price_desc':
      sorted.sort((a, b) => b.price - a.price);
      break;
    default:
      break;
  }

  return sorted;
}

// ─── Validation ────────────────────────────────────────────────────────────────

/**
 * Validates a template submission. Returns an array of error messages (empty = valid).
 */
export function validateSubmission(submission: TemplateSubmission): string[] {
  const errors: string[] = [];

  if (!submission.title || submission.title.length < 3 || submission.title.length > 100) {
    errors.push('Título deve ter entre 3 e 100 caracteres');
  }

  if (
    !submission.description ||
    submission.description.length < 10 ||
    submission.description.length > 500
  ) {
    errors.push('Descrição deve ter entre 10 e 500 caracteres');
  }

  if (!VALID_CATEGORIES.has(submission.category)) {
    errors.push('Categoria inválida');
  }

  if (
    !Array.isArray(submission.tags) ||
    submission.tags.length < 1 ||
    submission.tags.length > 10
  ) {
    errors.push('Deve ter entre 1 e 10 tags');
  }

  if (!VALID_FORMATS.has(submission.format)) {
    errors.push('Formato inválido');
  }

  if (typeof submission.price !== 'number' || submission.price < 0) {
    errors.push('Preço deve ser um número não-negativo');
  }

  return errors;
}

/**
 * Validates a review. Returns an array of error messages (empty = valid).
 */
export function validateReview(
  review: Omit<TemplateReview, 'id' | 'createdAt'>
): string[] {
  const errors: string[] = [];

  if (
    typeof review.rating !== 'number' ||
    review.rating < 1 ||
    review.rating > 5 ||
    !Number.isInteger(review.rating)
  ) {
    errors.push('Avaliação deve ser um inteiro entre 1 e 5');
  }

  if (!review.comment || review.comment.length < 5 || review.comment.length > 500) {
    errors.push('Comentário deve ter entre 5 e 500 caracteres');
  }

  return errors;
}

// ─── Rating ────────────────────────────────────────────────────────────────────

/**
 * Computes the average rating rounded to 1 decimal place.
 * Returns 0 for an empty array.
 */
export function computeAverageRating(reviews: TemplateReview[]): number {
  if (reviews.length === 0) return 0;
  const sum = reviews.reduce((acc, r) => acc + r.rating, 0);
  return Math.round((sum / reviews.length) * 10) / 10;
}

// ─── Pagination ────────────────────────────────────────────────────────────────

export function paginateResults(
  templates: MarketplaceTemplate[],
  page: number,
  pageSize: number
): MarketplaceSearchResult {
  const safePage = Math.max(1, page);
  const safePageSize = Math.max(1, pageSize);
  const total = templates.length;
  const totalPages = Math.max(1, Math.ceil(total / safePageSize));
  const clampedPage = Math.min(safePage, totalPages);
  const start = (clampedPage - 1) * safePageSize;
  const end = start + safePageSize;
  const pageTemplates = templates.slice(start, end);

  return {
    templates: pageTemplates,
    total,
    page: clampedPage,
    pageSize: safePageSize,
    totalPages,
    hasMore: clampedPage < totalPages,
  };
}

// ─── Stats ─────────────────────────────────────────────────────────────────────

/**
 * Count of templates per category.
 */
export function getCategoryStats(
  templates: MarketplaceTemplate[]
): Record<TemplateCategory, number> {
  const stats = {} as Record<TemplateCategory, number>;
  for (const cat of TEMPLATE_CATEGORIES) {
    stats[cat.value] = 0;
  }
  for (const t of templates) {
    if (stats[t.category] !== undefined) {
      stats[t.category]++;
    }
  }
  return stats;
}

/**
 * Returns the top N tags ordered by frequency.
 */
export function getPopularTags(
  templates: MarketplaceTemplate[],
  limit = 10
): { tag: string; count: number }[] {
  const counts = new Map<string, number>();
  for (const t of templates) {
    for (const tag of t.tags) {
      const normalised = tag.toLowerCase();
      counts.set(normalised, (counts.get(normalised) ?? 0) + 1);
    }
  }

  return Array.from(counts.entries())
    .map(([tag, count]) => ({ tag, count }))
    .sort((a, b) => b.count - a.count)
    .slice(0, limit);
}

// ─── Helpers ───────────────────────────────────────────────────────────────────

export function isTemplateFree(template: MarketplaceTemplate): boolean {
  return template.price === 0;
}

/**
 * Returns true if the user can review this template.
 * Rules: can't review own template, can't review twice.
 */
export function canUserReview(
  userId: string,
  template: MarketplaceTemplate,
  existingReviews: TemplateReview[]
): boolean {
  if (template.authorId === userId) return false;
  if (existingReviews.some((r) => r.userId === userId)) return false;
  return true;
}

/**
 * Formats a price in BRL or USD.
 */
export function formatPrice(price: number, currency: 'BRL' | 'USD'): string {
  if (price === 0) {
    return 'Grátis';
  }

  if (currency === 'BRL') {
    return `R$ ${price.toFixed(2).replace('.', ',')}`;
  }

  return `$${price.toFixed(2)}`;
}
